var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>때리지 마, 때리지 말아 주세요, 때리지…… 끄아아아악!!</color>","JPN":"<color=#ffd34c>やめてくだ……やめてください、このとおりです……ぐわああああっ！！</color>","ENG":"<color=#ffd34c>Stop hitting me, stop hitting me, please stop hit… Aaack!!</color>","TWN":"<color=#ffd34c>別打我，拜託別打我，別打……啊啊啊！！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사, 사람 살려……! 그냥 사채업자라고 했잖아……!! 얘기가 다르다고!</color>","JPN":"<color=#ffd34c>た、助けてくれ！　ただの闇金業者と言ってたじゃないか……！！　話が違うぞ！</color>","ENG":"<color=#ffd34c>H-help!!! This was supposed to be just a loan shark!! Not some monster!</color>","TWN":"<color=#ffd34c>救…救命……！你不說你只是個放高利貸的嗎……！騙人！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지원! 지원이 필요해! 있는 놈들은 전부 불러!!</color>","JPN":"<color=#ffd34c>応援！　応援が必要だ！　待機中のやつを全員集めろ！</color>","ENG":"<color=#ffd34c>Backup! We need back up now! Call in everyone!</color>","TWN":"<color=#ffd34c>支援！需要支援！有多少人都給我叫來！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"적대 개체가 감지되지 않습니다. 상담 상태를 해제합니다.","JPN":"敵対個体が残っていないことを確認。相談状態を解除します。","ENG":"Hostility no longer detected. Disengaging interrogation mode.","TWN":"沒有感應到敵對個體，解除諮詢狀態。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"커뮤니케이션 재개 전에, 협력사와의 통신을 시도합니다.","JPN":"コミュニケーションを再開する前に、協力会社との通信を試みます。","ENG":"Attempting to contact partner firm prior to reengaging.","TWN":"在重啟溝通前，先和合作公司聯絡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"뭡니까. 당신은.","JPN":"誰ですか、あなたは。","ENG":"Who are you? Identify yourself.","TWN":"你是誰？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"떠돌이 연주자, 셰나랍니다.","JPN":"さすらいの演奏者、シェナです。","ENG":"Oh, I'm just a wondering troubadour, Shena.","TWN":"浪人演奏家 世娜！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"무식하게 힘만 센 줄 알았더니 재빠르기까지 하네.","JPN":"バカみたいに力だけ強いと思ったら素早いじゃない。","ENG":"I thought you were just a strong brute, but you're quick on your feet too.","TWN":"我還以為你頭腦簡單空有蠻力，沒想到手腳也滿俐落的嘛～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"좀 귀엽다, 너. 이 벌레들이랑 같이 죽여 버리려고 했는데.","JPN":"あなた、ちょっとかわいいわね。この虫けらどもと一緒に殺そうとしたんだけど。","ENG":"I kind of like you. And to think I was about to smash you with the rest of these worms.","TWN":"有點可愛，本來是想送你和這些蟲子一起上西天的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……무력화된 적대 개체들의 생명 반응 소멸. 이들과 적대 관계입니까.","JPN":"……無力化した敵性個体の生命反応消滅。彼らとは敵対関係ですか。","ENG":"…No vital signs detected in neutralized hostiles. Were these men your enemies?","TWN":"……昏厥的敵對個體生命跡象消失。你和他們不是一夥的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"질문하는 것 좀 봐. 멍청해서 더 귀엽네.","JPN":"何そのバカみたいな質問は。それもかわいいけど。","ENG":"Aww, you little dum-dum with your stupid questions! You're so cute I could just eat you up!","TWN":"你聽聽你問的問題，真是傻到可愛呢～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너 어디서 생산된 로봇이야? 나도 너랑 같은 기종으로 하나 구입할 수 있을까?","JPN":"あなたはどこで生産されたロボットなの？　私もあなたと同じ機種が一台ほしいわ。","ENG":"So where do they manufacture robots like you? Think I could buy one?","TWN":"你是哪裡生產的機器人？我也可以買個和你一樣的機種嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"대답하십시오.","JPN":"答えてください。","ENG":"You have not answered my question.","TWN":"請回答我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 알짜배기 재미만 빼먹을 생각이었는데, 진짜가 여기 있었네.","JPN":"フフ、あまり期待してなかったけど、面白い子だったのね。","ENG":"Heh. I was almost getting bored with all of this 'til you showed up.","TWN":"呵呵～原本只是想來找點樂子，沒想到你真的在這裡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"묵비권을 행사하겠다면, 물리적인 설득을 시도하겠습니다.","JPN":"黙秘権を行使するなら、物理的な説得を試みます。","ENG":"Refusal to comply will be met with kinetic persuasion.","TWN":"若你要行使緘默權，那我只好用力量說服你。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저런, 시작하자마자 클라이맥스로 치닫는 곡은 연주하기 심심하잖아.","JPN":"あら、始まったばかりなのにクライマックスに向う曲は、演奏する側がつまらないじゃない。","ENG":"Oh my. It's no fun playing a piece that starts with the climax.","TWN":"真是的，沒有超潮迭起的曲子，演奏起來不是很無趣嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그리고 우리 관계도 분명 예외는 아닐 거야. 호라이즌.","JPN":"そして私たちの関係も例外ではないでしょう、ホライズン。","ENG":"I'm sure the same goes for you and me, Horizon.","TWN":"而且我們的關係沒這麼生疏吧，地平線？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"입방정이 심한 분이시군요.","JPN":"無駄なおしゃべりが多い方ですね。","ENG":"You offer too many empty words.","TWN":"看來你話非常多。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"미안. 무대 체질이라.","JPN":"ごめんね、役者気質なの。","ENG":"Sorry. I'm such a stage person.","TWN":"不好意思，天生適合在舞台上。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"나는 셰나, 졸지에 제프티 바이오테크의 경호실장을 맡고 있지만 일단은 예술가거든.","JPN":"私はシェナ。事情があってジェフティ・バイオテックで警護室長の仕事をしているけど、一応芸術家でね。","ENG":"I may be the Head of Security at Jehuty Biotech for now, but I've always been an artist first.","TWN":"我是世娜，突然就當上傑夫堤生物科技的護衛室長，但其實我是藝術家。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇다 보니 예술의 길을 걸으려 하는 아이를 외면할 수가 없어.","JPN":"だからかしら、芸術の道を歩もうとする子を見つけたら、見て見ぬふりはできないの。","ENG":"That's why I couldn't turn a blind eye to a child who wanted to walk the path of an artist.","TWN":"因此無法忽視想踏上藝術之路的孩子。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼에 대한 조롱이라면 묵과하지 않겠습니다.","JPN":"レイチェルを嘲弄するつもりなら見過ごしません。","ENG":"I will not tolerate such mockery of Rachel, if that is what you intend.","TWN":"你是在嘲諷瑞秋的話，那我不會放過你的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"살릴 수 있어. 그 아이.","JPN":"助かるわよ、その子。","ENG":"You can save her, you know. That kid.","TWN":"我有辦法救活她。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아. 물론 너한테는 <color=#ffd34c>이번에는</color>이란 단서가 붙겠지만.","JPN":"ああ、もちろんあなたには「<color=#ffd34c>今回は</color>」という但し書きがつくけど。","ENG":"Oh… Of course, I'll have to add a little caveat in your case. <color=#ffd34c>This time</color>, you can actually save her.","TWN":"當然，<color=#ffd34c>這次</color>線索就在你身上。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"……!","TWN":"……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐흠. 뒤도 안 돌아보고 가 버리네.","JPN":"ふーん、振り向きもせず行っちゃったわね。","ENG":"Hmm… She just disappeared without even looking back.","TWN":"哈，頭也不回地走掉欸？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 뭐……. 금방 다시 만날 테니까.","JPN":"……まあでも、すぐ会えるから。","ENG":"Oh well… We'll meet again soon anyway.","TWN":"反正……很快就又會再見面。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……이즌? 호라이즌…… 맞아……?","JPN":"……イズン？　ホライズン……なの……？","ENG":"…rizon? Is that you… Horizon?","TWN":"……地平線？……是你嗎……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다. 접니다.","JPN":"はい、私です。","ENG":"Yes. It's me.","TWN":"是的，就是我。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그…… 사람들…… 어디……","JPN":"あの……人たち……どこに……","ENG":"Those people… Where… are they…","TWN":"那……那些人……在哪……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"안심하십시오. 현재 전원 항거 불능 상태입니다.","JPN":"安心してください。現在は全員抵抗不能状態です。","ENG":"Don't worry. They are all currently incapacitated.","TWN":"你放心，那些人現在全都處於，無法阻止我們的狀態。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"손이……. 안 움직여…….","JPN":"手が……動かない……","ENG":"My hand… I can't move my hand…","TWN":"我的手……動不了……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"나, 바보같이……. 그냥……. 원장님 말 들었으면…….","JPN":"アタシ、バカなこと……ただ……院長の言うことを聞いておけば……","ENG":"I was such a fool… I should have just… listened to the headmaster…","TWN":"我這個笨蛋……早知道……就聽院長的話……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……제가 업어드리겠습니다.","JPN":"……私が背負います。","ENG":"…I will carry you.","TWN":"……我揹你。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"조금만 버티십시오. 병원으로 옮겨드리겠습니다.","JPN":"もう少し耐えてください。病院まで運びます。","ENG":"Hang in there. I will take you to the hospital.","TWN":"再撐一下，我帶你去醫院。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……이런. 한참 늦어 버렸군.","JPN":"……まいったな、ずいぶん遅れてしまったか。","ENG":"…Damn. Looks like I got here too late.","TWN":"……該死！晚了一步！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"생체정보 확인. 강민우. 문에서 비키십시오.","JPN":"生体情報確認。マツダ・シュウイチ。ドアから退いてください。","ENG":"Biometrics identified. Kang Minwoo. Step aside from the entrance.","TWN":"生物資訊確認，姜民宇。請不要擋住門。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그만둬. 호라이즌. 지금 네가 무작정 레이첼을 옮기다간 그대로 죽을 수도 있어.","JPN":"やめろ、ホライズン。今むやみにレイチェルを運んだら死ぬかもしれないぞ。","ENG":"Don't do it, Horizon. If you move Rachel like that, she could die.","TWN":"地平線，你別這樣。你這樣隨便亂動瑞秋，她很可能會死掉。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 한 시라도 신속히 병원으로 이송해야 합니다.","JPN":"だから一刻も早く病院に移送する必要があります。","ENG":"All the more reason to transport her to the hospital immediately.","TWN":"所以必須盡快送她去醫院。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다시 생각해. 레이첼은 지금 숨 쉬기도 괴로운 상태야.","JPN":"よく考えろ。レイチェルは今呼吸するのも苦しい状態だ。","ENG":"Think about it. It hurts her to even breathe right now.","TWN":"你想想，瑞秋現在連呼吸都有困難。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"혹시나 해서 장갑차를 몰고 왔다. 안에 부상자용 침대도 있어.","JPN":"念のため装甲車で来たんだ。中に負傷者用ベッドもある。","ENG":"I brought the APC just in case. There's a stretcher in there.","TWN":"以防萬一，我有把裝甲車開來，車上有傷者專用的病床。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그 상태에서 무리하게 옮기면 버티지 못해.","JPN":"その状態で無理やり運んでしまうと、体が持たないぞ。","ENG":"She won't last if you move her recklessly in that condition.","TWN":"在這種狀態下勉強移動的話，她會撐不住的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정말 그 애를 살리고 싶다면…… 내 말에 따라.","JPN":"本当にその子を助けたいなら……俺の言うことを聞け。","ENG":"If you really want to save her… do as I say.","TWN":"你要是真的想救她……就聽我的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"들것을 가져와 주시겠습니까. 부탁드립니다.","JPN":"担架を持ってきてもらえますか、お願いします。","ENG":"Then could you bring the stretcher? Please…","TWN":"可以把擔架拿過來嗎？拜託你。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};